import SongCard from '@/components/SongCard';
import { Play } from 'lucide-react';

const FEATURED_SONGS = [
  { id: "dQw4w9WgXcQ", title: "Never Gonna Give You Up", artist: "Rick Astley", thumbnail: "https://i.ytimg.com/vi/dQw4w9WgXcQ/hqdefault.jpg" },
  { id: "kJQP7kiw5Fk", title: "Despacito", artist: "Luis Fonsi", thumbnail: "https://i.ytimg.com/vi/kJQP7kiw5Fk/hqdefault.jpg" },
  { id: "3tmd-ClpJxA", title: "7 Rings", artist: "Ariana Grande", thumbnail: "https://i.ytimg.com/vi/3tmd-ClpJxA/hqdefault.jpg" },
  { id: "kOTsn_wGDLE", title: "Old Town Road", artist: "Lil Nas X", thumbnail: "https://i.ytimg.com/vi/kOTsn_wGDLE/hqdefault.jpg" },
  { id: "c8RUi5ubvsI", title: "Shape of You", artist: "Ed Sheeran", thumbnail: "https://i.ytimg.com/vi/c8RUi5ubvsI/hqdefault.jpg" }
];

const MIXES = [
  { color: 'from-purple-600/20', title: 'Daily Mix 1', subtitle: 'Pop, Dance, Chill' },
  { color: 'from-blue-600/20', title: 'Rap Caviar', subtitle: 'Hip-hop, Trap' },
  { color: 'from-emerald-600/20', title: 'Chill Hits', subtitle: 'Relax, Indie' }
];

export default function Home() {
  return (
    <div className="flex-1 h-screen overflow-y-auto bg-[#121212] text-white">
      {/* Dynamic Header Background */}
      <div className="relative bg-gradient-to-b from-[#222222] to-[#121212] px-6 pt-20 pb-8">
        <h1 className="text-3xl font-bold tracking-tight mb-8">Good evening</h1>
        
        {/* Top Mixes - Grid Layout (Spotify Style) */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {MIXES.map((mix, idx) => (
            <div 
              key={idx}
              className="group flex items-center bg-white/5 hover:bg-white/10 rounded-md overflow-hidden transition-all cursor-pointer relative"
            >
              <div className={`w-20 h-20 bg-gradient-to-br ${mix.color} flex items-center justify-center shadow-lg`}>
                <Play fill="currentColor" className="text-white opacity-0 group-hover:opacity-100 transition-opacity translate-y-2 group-hover:translate-y-0 duration-300" />
              </div>
              <div className="p-4 flex-1">
                <p className="font-bold truncate">{mix.title}</p>
              </div>
              {/* Play Button Overlay */}
              <button className="mr-4 opacity-0 group-hover:opacity-100 transition-all bg-[#1ed760] p-3 rounded-full shadow-xl text-black translate-y-2 group-hover:translate-y-0">
                <Play size={20} fill="black" />
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Recommended Section */}
      <main className="px-6 py-8">
        <div className="flex items-end justify-between mb-6">
          <div>
            <h2 className="text-2xl font-bold hover:underline cursor-pointer">Recommended for you</h2>
            <p className="text-sm text-[#b3b3b3] mt-1">Based on your recent listening</p>
          </div>
          <span className="text-xs font-bold text-[#b3b3b3] uppercase tracking-widest hover:underline cursor-pointer">Show all</span>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
          {FEATURED_SONGS.map(song => (
            <div key={song.id} className="bg-[#181818] p-4 rounded-md hover:bg-[#282828] transition-all duration-300 group cursor-pointer">
              <div className="relative aspect-square mb-4 shadow-2xl">
                <img 
                  src={song.thumbnail} 
                  alt={song.title}
                  className="object-cover w-full h-full rounded-md"
                />
                <button className="absolute bottom-2 right-2 opacity-0 group-hover:opacity-100 group-hover:translate-y-[-8px] transition-all bg-[#1ed760] p-3 rounded-full shadow-xl text-black">
                   <Play size={20} fill="black" />
                </button>
              </div>
              <h3 className="font-bold text-sm truncate mb-1">{song.title}</h3>
              <p className="text-xs text-[#b3b3b3] line-clamp-2 leading-relaxed">
                {song.artist || 'Artist'}
              </p>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}